class TempFile {
  constructor(path) {
    this.path = path;
    this.handle = fs.openSync(path, 'w');
  }

  write(data) {
    fs.writeSync(this.handle, data);
  }

  [Symbol.dispose]() {
    fs.closeSync(this.handle);
    fs.unlinkSync(this.path);
    console.log('Cleaned up!');
  }
}

using file = new TempFile('/tmp/data');
file.write('hello');
// Auto-deleted when scope exits
